@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Manage all registered users and their roles.</p>

@if (users is null)
{
    <p><em>Loading users...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Display Name</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var u in users)
            {
                <tr>
                    <td>@u.Email</td>
                    <td>@u.DisplayName</td>
                    <td>@string.Join(", ", u.Roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<UserWithRoles>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        users = new List<UserWithRoles>();
        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            users.Add(new UserWithRoles(user.Email!, user.DisplayName ?? "", roles));
        }
    }

    private record UserWithRoles(string Email, string DisplayName, IList<string> Roles);
}

